(260, 1, '2021-12-22 17:11:42', '2021-12-22 16:11:42', '<!-- wp:columns {\"align\":\"wide\"} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Get in touch with us to get more information about our services and to learn how we may help you solve your test and measurement challenges. Give us a call or use the form below to get in touch.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"className\":\"is-style-default\"} -->\n<div class=\"wp-block-group is-style-default\"><!-- wp:columns {\"className\":\"is-style-default\"} -->\n<div class=\"wp-block-columns is-style-default\"><!-- wp:column {\"width\":\"170px\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:170px\"><!-- wp:image {\"id\":246,\"sizeSlug\":\"thumbnail\",\"linkDestination\":\"none\",\"className\":\"is-style-rounded\"} -->\n<figure class=\"wp-block-image size-thumbnail is-style-rounded\"><img src=\"http://31.217.196.224/~jaxedsws/legacy/wp-content/uploads/2021/12/Sundqvist_Anton-150x150.jpg\" alt=\"Anton Sundqvist\" class=\"wp-image-246\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"\"} -->\n<div class=\"wp-block-column\"><!-- wp:paragraph {\"style\":{\"typography\":{\"lineHeight\":\"1.5\"}}} -->\n<p style=\"line-height:1.5\">Anton Sundqvist<br><a href=\"tel:+358447272425\">+358 (0) 44 727 2425<br></a><a href=\"mailto:anton.sundqvist@astemes.com\">anton.sundqvist@astemes.com<br></a><a href=\"https://www.linkedin.com/in/anton-sundqvist/\" target=\"_blank\" rel=\"noreferrer noopener\">https://linkedin.com/in/anton-sundqvist</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Contact', '', 'inherit', 'closed', 'closed', '', '151-revision-v1', '', '', '2021-12-22 17:11:42', '2021-12-22 16:11:42', '', 151, 'http://31.217.196.224/~jaxedsws/legacy/?p=260', 0, 'revision', '', 0);
INSERT INTO `cihp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(261, 1, '2021-12-31 11:21:45', '2021-12-31 10:21:45', '<!-- wp:heading {\"className\":\"alignwide has-text-align-wide\",\"style\":{\"typography\":{\"lineHeight\":\"1.1\",\"fontSize\":\"90px\"}}} -->\n<h2 class=\"alignwide has-text-align-wide\" style=\"font-size:90px;line-height:1.1\">Test and Measurement Solutions<p class=\"has-text-align-wide\"></p></h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {\"align\":\"wide\"} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Astemes is a solutions provider for test and measurement applications. We develop systems to automate testing of electro-mechanical products through the entire product life cycle. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We are your partner in test automation. From early proof-of-concepts and prototyping, through validation and verification, production testing, and beyond. We have high certified competency in the NI LabVIEW and NI TestStand software as well as extensive experience using and integrating various measurement devices and instruments. We are also highly effective working in Python and comfortable with C++ and Java.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3} -->\n<h3>Software Development</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We develop high quality industrial software for test and measurement applications. We provide software development services based on your needs, working either as part of your team or independently. Because communication is at least as important as problem solving in software engineering, we prefer to work incrementally where we continuously deliver business value and gather feedback.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3} -->\n<h3>Turn-Key Solutions</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The best results are achieved when we get involved early on during requirement gathering and design specification. After this phase we lead the project and find the best components and subcontractors, to deliver according to the agreed upon schedule. We work hard to keep the customer involved through the whole project to validate our understanding and steer the project along the way.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3} -->\n<h3>Training</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We offer tailored training, presentations and workshops related to testing, process and software development. We either schedule the sessions over a shorter time period or define a cadence with sessions spread out over a longer period. The content may be delivered either on-site, remotely, or as a combination of the two. We also offer professional code reviews and pair programming.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:heading -->\n<h2>How We Work</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We use industry standard technologies and proven frameworks to efficiently produce high quality software. By leveraging open source and proprietary software for common and generic tasks, we can focus on the core domain problems and avoid reinventing known solutions. This also reduces the maintenance cost and total cost of ownership over the lifecycle of the system.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Our project model starts with a defining phase where the needs and requirements are assessed. This phase may include a pre-study to clarify the requirements. The outcome of this first phase should be a verified understanding of the needs and a proposal for a solution. In many cases the actual requirements are not known at this stage and they will evolve over the course of the project.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Before development starts, milestones for deliverables should be defined and a feedback cadence should be agreed upon. During development we think it is important to be transparent with the progress and raise potential issues as soon as possible. After commissioning, a support plan may be defined to ensure the system is maintained and continues to provide value over time.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->', 'Astemes', '', 'inherit', 'closed', 'closed', '', '16-revision-v1', '', '', '2021-12-31 11:21:45', '2021-12-31 10:21:45', '', 16, 'http://31.217.196.224/~jaxedsws/legacy/?p=261', 0, 'revision', '', 0),
