tions\":{\"1\":{\"type\":\"message\",\"message\":\"<p>Thanks for contacting us! We will be in touch with you shortly.<\\/p>\",\"message_scroll\":\"1\",\"page\":\"150\",\"redirect\":\"\"}}},\"meta\":{\"template\":\"4dbf022985a4fe4bda4a80365011a3a0\"}}', 'Contact Us', '', 'publish', 'closed', 'closed', '', 'simple-contact-form', '', '', '2021-11-12 18:38:31', '2021-11-12 17:38:31', '', 0, 'http://www.astemes.com/staging/?post_type=wpforms&#038;p=173', 0, 'wpforms', '', 0),
(175, 1, '2021-11-12 17:30:19', '2021-11-12 16:30:19', '<!-- wp:columns {\"align\":\"wide\"} -->\n<div class=\"wp-block-columns alignwide\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Get in touch with us to get more information about our services and to learn how we may help you solve your test and measurement challenges.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:wpforms/form-selector {\"formId\":\"173\",\"displayTitle\":false} /--></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->', 'Contact', '', 'inherit', 'closed', 'closed', '', '151-revision-v1', '', '', '2021-11-12 17:30:19', '2021-11-12 16:30:19', '', 151, 'http://www.astemes.com/staging/?p=175', 0, 'revision', '', 0),
